import java.util.PriorityQueue;
class Solution {
    public int kthLargestElementInAnArray(int[] data) {
        int k = 3; // Example value for k, can be modified as needed
        PriorityQueue<Integer> minHeap = new PriorityQueue<>(k);
        for (int num : data) {
            minHeap.offer(num);
            if (minHeap.size() > k) {
                minHeap.poll();
            }
        }
        return minHeap.peek();
    }
}

