package main

import (
    "container/heap"
)

type MinHeap []int

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x interface{}) {
    *h = append(*h, x.(int))
}

func (h *MinHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func kthLargestElementInAnArray(data []int) int {
    k := 0
    heap := &MinHeap{}
    heap.Init()

    for _, num := range data {
        heap.Push(num)
        if heap.Len() > k {
            heap.Pop()
        }
    }

    return (*heap)[0]
}

