using System;
using System.Collections.Generic;

public class Solution {
    public int kthLargestElementInAnArray(int[] data) {
        int k = 3; // You can change k to any desired value
        if (data.Length < k) return -1;

        var minHeap = new SortedSet<int>();
        foreach (var num in data) {
            minHeap.Add(num);
            if (minHeap.Count > k) {
                minHeap.Remove(minHeap.Min);
            }
        }
        return minHeap.Min;
    }
}
